SELECT count(*) FROM title, movie_companies, company_name, company_type, movie_keyword, kind_type, keyword, cast_info WHERE movie_companies.movie_id = title.id AND movie_companies.company_id = company_name.id AND movie_companies.company_type_id = company_type.id AND movie_keyword.movie_id = title.id AND title.kind_id = kind_type.id AND movie_keyword.keyword_id = keyword.id AND cast_info.movie_id = title.id;